import{_ as a,o as t,c as i,a3 as n}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"35. Transition To New Theatre Technician Structure","description":"","frontmatter":{"title":"35. Transition To New Theatre Technician Structure","eba":"Health Allied & Managers Admin 2021-2025","topics":["classifications"]},"headers":[],"relativePath":"ebas/has-managers-admin/health-allied-services/classification-staffing/35-transition-to-new-theatre-technician-structure.md","filePath":"ebas/has-managers-admin/health-allied-services/classification-staffing/35-transition-to-new-theatre-technician-structure.md"}'),r={name:"ebas/has-managers-admin/health-allied-services/classification-staffing/35-transition-to-new-theatre-technician-structure.md"};function s(c,e,h,o,l,T){return t(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="_35-transition-to-new-theatre-technician-structure" tabindex="-1">35. Transition To New Theatre Technician Structure <a class="header-anchor" href="#_35-transition-to-new-theatre-technician-structure" aria-label="Permalink to &quot;35. Transition To New Theatre Technician Structure&quot;">​</a></h1><p><strong>35.1</strong> From FFPPOA 1 July 2021, Employees classified as Theatre Technicians will translate to the new Theatre Technician classification structure as follows</p><p>Current classification New classification Theatre Technician Grade 1 Theatre Technician in Training - Grade 1 Theatre Technician Grade 2</p><p>Theatre Technician Grade 3 Theatre Technician in Training - Grade 2 Theatre Technician Grade 4 Theatre Technician Grade 3 Theatre Technician Grade 5 Theatre Technician Grade 4 Theatre Technician Grade 6 Theatre Technician Grade 5 Grade 6 Theatre Technicians who Liver Transplant Technologist work in the Liver Transplant Team at Austin Health translation only applies to Liver Transplant Team at Austin Health</p><p><strong>35.2</strong> Within 3 months of the commencement of the Agreement, the Employers will review the existing Employees classified as Theatre Technicians and confirm in writing to those Employees:</p><p><strong>(a)</strong> to which classification they have translated, effective from FFPPOA 1 July</p><p><strong>(b)</strong> whether their duties change as a result of the translation</p><p><strong>(c)</strong> back payment of wages (if any) effective from FFPPOA 1 July 2021</p><p><strong>35.3</strong> Where an Employee disagrees with this re-classification, in the first instance the dispute will be dealt with by the AIC. If the matter remains in dispute, it will be dealt with in accordance with Section 1 <a href="/eba/ebas/has-managers-admin/health-allied-services/allowances/17-reimbursement-of-expenses-dhsv.html">clause 17</a> (Dispute Resolution Procedure).</p>',9)])])}const f=a(r,[["render",s]]);export{u as __pageData,f as default};
